import asyncio
from anthropic import AsyncAnthropic, RateLimitError, APIStatusError

client = AsyncAnthropic()

STATIC_FALLBACKS = {
    "greeting": "Hello! I am temporarily unavailable but will be back shortly.",
    "default": (
        "I am currently unable to process your request due to a service interruption. "
        "Your message has been saved and you will receive a response as soon as possible. "
        "For urgent issues, please contact support."
    ),
}

async def respond_with_fallback(query: str, history: list) -> dict:
    """
    Try: live Claude -> degraded Haiku -> semantic cache -> static fallback.
    Returns {text, source, cached} where source indicates which layer responded.
    """
    # Layer 1: Full Claude
    try:
        resp = await asyncio.wait_for(
            client.messages.create(
                model="claude-opus-4-8", max_tokens=2048, messages=history
            ),
            timeout=30.0,
        )
        text = resp.content[0].text
        await store_response(query, text)
        return {"text": text, "source": "live", "cached": False}
    except (RateLimitError, APIStatusError, asyncio.TimeoutError):
        pass

    # Layer 2: Degraded Haiku (no tools, shorter)
    try:
        resp = await asyncio.wait_for(
            client.messages.create(
                model="claude-haiku-4-5-20251001", max_tokens=512,
                messages=[{"role": "user", "content": query}],
            ),
            timeout=15.0,
        )
        return {"text": resp.content[0].text, "source": "degraded", "cached": False}
    except Exception:
        pass

    # Layer 3: Semantic cache
    cached = await cached_response(query)
    if cached:
        return {
            "text": cached + "\n\n*(This response was retrieved from cache and may not reflect the latest information.)*",
            "source": "cache",
            "cached": True,
        }

    # Layer 4: Static fallback
    return {"text": STATIC_FALLBACKS["default"], "source": "static", "cached": False}

// useOfflineMode.ts - detect offline, queue messages, sync on reconnect
import { useState, useEffect, useRef } from "react";

interface PendingMessage { id: string; content: string; sessionId: string; }

export function useOfflineMode(sessionId: string) {
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [pending, setPending] = useState<PendingMessage[]>([]);
  const syncingRef = useRef(false);

  useEffect(() => {
    const setOnline  = () => setIsOnline(true);
    const setOffline = () => setIsOnline(false);
    window.addEventListener("online",  setOnline);
    window.addEventListener("offline", setOffline);
    return () => {
      window.removeEventListener("online",  setOnline);
      window.removeEventListener("offline", setOffline);
    };
  }, []);

  // Sync queued messages when connection is restored
  useEffect(() => {
    if (!isOnline || pending.length === 0 || syncingRef.current) return;
    syncingRef.current = true;
    (async () => {
      for (const msg of pending) {
        try {
          await fetch(`/chat/${msg.sessionId}/message`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ content: msg.content }),
          });
          setPending(q => q.filter(m => m.id !== msg.id));
        } catch {
          break;  // Stop on failure; will retry next reconnect
        }
      }
      syncingRef.current = false;
    })();
  }, [isOnline, pending, sessionId]);

  const sendOrQueue = async (content: string): Promise<boolean> => {
    if (isOnline) return false;   // caller should send normally
    const id = crypto.randomUUID();
    setPending(q => [...q, { id, content, sessionId }]);
    // Persist to IndexedDB for page-reload survival
    await persistToIDB({ id, content, sessionId });
    return true;   // queued
  };

  return { isOnline, pendingCount: pending.length, sendOrQueue };
}

// EscalationCard.tsx - shown when the agent cannot help
export function EscalationCard({
  ticketId,
  onLiveChat,
}: { ticketId?: string; onLiveChat?: () => void }) {
  return (
    <div className="rounded-xl bg-slate-800 border border-slate-600 p-4 my-2 text-sm">
      <p className="text-slate-200 font-medium mb-2">
        I have escalated this to our support team.
      </p>
      {ticketId && (
        <p className="text-slate-400 text-xs mb-3">Ticket ID: <code>{ticketId}</code></p>
      )}
      <div className="flex gap-2">
        {onLiveChat && (
          <button onClick={onLiveChat}
                  className="bg-indigo-600 hover:bg-indigo-500 text-white text-xs px-3 py-1.5 rounded-lg">
            Start live chat
          </button>
        )}
        <button className="text-slate-400 hover:text-slate-200 text-xs underline">
          View ticket status
        </button>
      </div>
    </div>
  );
}
